<template><view class="page"><view class="card"><text class="title">{{assetName(type)}}明细</text><view v-for="r in records" :key="r.id" class="rec"><text>{{r.title||r.bizType}}</text><text class="price">{{r.amount}}</text><text class="muted">{{r.createdAt}}</text></view><view v-if="!records.length" class="muted">暂无记录</view></view></view></template><script setup lang="ts">import { ref } from 'vue';import { onLoad } from '@dcloudio/uni-app';import { assetApi } from '@/services/asset';import { listOf,assetName } from '@/utils/format';const type=ref('balance'),records=ref<any[]>([]);onLoad(async(o:any)=>{type.value=o.type||o.tab||'balance';records.value=listOf((await assetApi.records(type.value)).data)})</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{font-size:34rpx;font-weight:900}.rec{padding:22rpx 0;border-bottom:1rpx solid #eee7db;display:flex;flex-direction:column;gap:8rpx}.price{color:#b97700;font-weight:900}.muted{color:#8d8175;font-size:24rpx}</style>
